                {f.severity}
              </span>
              <span style={{ color: "var(--parchment-dim)", fontSize: "0.6rem" }}>
                {f.category}
              </span>
            </div>
            <p style={{ color: "var(--parchment)", margin: "0.2rem 0" }}>{f.detail}</p>
            {f.suggestedAction && (
              <p style={{ color: "var(--gold-dim)", fontSize: "0.7rem", fontStyle: "italic", margin: 0 }}>
                Suggested: {f.suggestedAction}
              </p>
            )}
          </div>
        ))}
      </div>
    </details>
  );
}

